arguments.command:
# Check which section the addresses belong to
readelf -S /tmp/monosgen_debug.so | grep -E '^\s+\[' | awk '{
  if (NF >= 7) {
    name=$2; addr=$4; size=$6; 
    a=strtonum("0x"addr); s=strtonum("0x"size);
    if (a <= 0x2f4b20 && a+s > 0x2f4b20) print "0x2f4b20 in section:", name, "addr:", addr, "size:", size
    if (a <= 0x2f4c84 && a+s > 0x2f4c84) print "0x2f4c84 in section:", name, "addr:", addr, "size:", size
  }
}'

